//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageautoscalingimport("reflect""testing""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/autoscaling")funcTestExpandStepAdjustments(t*testing.T){t.Parallel()expanded:=[]interface{}{map[string]interface{}{"metric_interval_lower_bound":"1.0","metric_interval_upper_bound":"2.0","scaling_adjustment":1,},}parameters,err:=ExpandStepAdjustments(expanded)iferr!=nil{t.Fatalf("bad:%#v",err)}expected:=&autoscaling.StepAdjustment{MetricIntervalLowerBound:aws.Float64(1.0),MetricIntervalUpperBound:aws.Float64(2.0),ScalingAdjustment:aws.Int64(1),}if!reflect.DeepEqual(parameters[0],expected){t.Fatalf("Got:\n\n%#v\n\nExpected:\n\n%#v\n",parameters[0],expected)}}funcTestFlattenStepAdjustments(t*testing.T){t.Parallel()expanded:=[]*autoscaling.StepAdjustment{{MetricIntervalLowerBound:aws.Float64(1.0),MetricIntervalUpperBound:aws.Float64(2.5),ScalingAdjustment:aws.Int64(1),},}result:=FlattenStepAdjustments(expanded)[0]ifresult==nil{t.Fatal("expectedresulttohavevalue,butgotnil")}ifresult["metric_interval_lower_bound"]!="1"{t.Fatalf("expectedmetric_interval_lower_boundtobe1,butgot%s",result["metric_interval_lower_bound"])}ifresult["metric_interval_upper_bound"]!="2.5"{t.Fatalf("expectedmetric_interval_upper_boundtobe2.5,butgot%s",result["metric_interval_upper_bound"])}ifresult["scaling_adjustment"]!=int64(1){t.Fatalf("expectedscaling_adjustmenttobe1,butgot%d",result["scaling_adjustment"])}}